#include <vector>
#include <string>
#include <unordered_map>
#include <unordered_set>
#include <algorithm>
using namespace std;

class Solution {
public:
    vector<string> getTopThree(int teamNum, vector<vector<string>>& matches) {
        // 1. 检查 teamNum 合法性
        if (teamNum < 3 || teamNum > 15) return {};

        // 2. 收集队伍并验证数量
        unordered_set<string> teamSet;
        for (auto& m : matches) {
            teamSet.insert(m[0]);
            teamSet.insert(m[3]);
        }
        vector<string> teams(teamSet.begin(), teamSet.end());
        if ((int)teams.size() != teamNum) return {};

        // 3. 初始化统计
        unordered_map<string, int> points, goalsFor, goalsAgainst;
        for (auto& t : teams) {
            points[t] = 0;
            goalsFor[t] = 0;
            goalsAgainst[t] = 0;
        }
        unordered_set<string> played;

        for (auto& m : matches) {
            string a = m[0], b = m[3];
            int ga = stoi(m[1]), gb = stoi(m[2]);

            // 记录对阵（字典序小的在前）
            string key = a < b ? a + "|" + b : b + "|" + a;
            played.insert(key);

            // 累加进球失球
            goalsFor[a] += ga;
            goalsAgainst[a] += gb;
            goalsFor[b] += gb;
            goalsAgainst[b] += ga;

            // 计分
            if (ga > gb) points[a] += 3;
            else if (ga < gb) points[b] += 3;
            else { points[a]++; points[b]++; }
        }

        // 4. 检查比赛场次
        int maxMatches = teamNum * (teamNum - 1) / 2;
        if ((int)matches.size() > maxMatches) return {};

        // 5. 检查每对队伍是否都有比赛
        int n = (int)teams.size();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                string key = teams[i] < teams[j]
                    ? teams[i] + "|" + teams[j]
                    : teams[j] + "|" + teams[i];
                if (played.find(key) == played.end()) return {};
            }
        }

        // 6. 检查积分+净胜球并列
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int gdI = goalsFor[teams[i]] - goalsAgainst[teams[i]];
                int gdJ = goalsFor[teams[j]] - goalsAgainst[teams[j]];
                if (points[teams[i]] == points[teams[j]] && gdI == gdJ) return {};
            }
        }

        // 7. 排序取前三
        sort(teams.begin(), teams.end(), [&](const string& a, const string& b) {
            if (points[a] != points[b]) return points[a] > points[b];
            int gdA = goalsFor[a] - goalsAgainst[a];
            int gdB = goalsFor[b] - goalsAgainst[b];
            return gdA > gdB;
        });
        return {teams.begin(), teams.begin() + min(3, (int)teams.size())};
    }
};
