    // 2. 收集所有队伍并去重
    const teamSet = new Set();
    for (const m of matches) {
        teamSet.add(m[0]);
        teamSet.add(m[3]);
    }
    const teams = [...teamSet];
    if (teams.length !== teamNum) return [];

    // 3. 初始化统计
    const points = {};
    const goalsFor = {};
    const goalsAgainst = {};
    for (const t of teams) {
        points[t] = 0;
        goalsFor[t] = 0;
        goalsAgainst[t] = 0;
    }
    const played = new Set();

    for (const m of matches) {
        const a = m[0], b = m[3];
        const ga = parseInt(m[1]), gb = parseInt(m[2]);

        // 记录已比赛的对阵
        const key = a < b ? a + '|' + b : b + '|' + a;
        played.add(key);

        // 累加进球与失球
        goalsFor[a] += ga;
        goalsAgainst[a] += gb;
        goalsFor[b] += gb;
        goalsAgainst[b] += ga;

        // 计分
        if (ga > gb) points[a] += 3;
        else if (ga < gb) points[b] += 3;
        else { points[a]++; points[b]++; }
    }

    // 4. 检查比赛场次
    if (matches.length > teamNum * (teamNum - 1) / 2) return [];

    // 5. 检查每对队伍是否都有比赛
    const n = teams.length;
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const key = teams[i] < teams[j]
                ? teams[i] + '|' + teams[j]
                : teams[j] + '|' + teams[i];
            if (!played.has(key)) return [];
        }
    }

    // 6. 检查积分+净胜球并列
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const gdI = goalsFor[teams[i]] - goalsAgainst[teams[i]];
            const gdJ = goalsFor[teams[j]] - goalsAgainst[teams[j]];
            if (points[teams[i]] === points[teams[j]] && gdI === gdJ) return [];
        }
    }

    // 7. 排序取前三
    teams.sort((a, b) => {
        if (points[b] !== points[a]) return points[b] - points[a];
        const gdA = goalsFor[a] - goalsAgainst[a];
        const gdB = goalsFor[b] - goalsAgainst[b];
        return gdB - gdA;
    });
    return teams.slice(0, Math.min(3, teams.length));
};
