#include <string.h>
#include <stdlib.h>

char** getTopThree(int teamNum, char*** matches, int matchesSize, int* returnSize) {
    // 返回空结果的处理函数
    void returnEmpty() {
        *returnSize = 0;
        // 返回空结果：分配一个以 NULL 结尾的空指针
    }

    // 1. 检查 teamNum 合法性
    if (teamNum < 3 || teamNum > 15) {
        *returnSize = 0;
        return NULL;
    }

    // 2. 收集队伍（去重）
    char* teams[16];
    int teamCount = 0;
    for (int i = 0; i < matchesSize; i++) {
        char** m = matches[i];
        for (int k = 0; k < 2; k++) {
            char* name = k == 0 ? m[0] : m[3];
            int found = 0;
            for (int j = 0; j < teamCount; j++) {
                if (strcmp(teams[j], name) == 0) { found = 1; break; }
            }
            if (!found) teams[teamCount++] = name;
        }
    }
    if (teamCount != teamNum) {
        *returnSize = 0;
        return NULL;
    }

    // 3. 统计积分、进球、失球
    int points[16] = {0};
    int goalsFor[16] = {0};
    int goalsAgainst[16] = {0};
    int played[256] = {0};  // 位图标记已比赛的对阵

    for (int k = 0; k < matchesSize; k++) {
        char** m = matches[k];
        char *a = m[0], *b = m[3];
        int ga = atoi(m[1]), gb = atoi(m[2]);

        // 找到队伍下标
        int ia = -1, ib = -1;
        for (int i = 0; i < teamCount; i++) {
            if (strcmp(teams[i], a) == 0) ia = i;
            if (strcmp(teams[i], b) == 0) ib = i;
        }

        // 标记对阵
        int pi = ia < ib ? ia : ib;
        int pj = ia < ib ? ib : ia;
        played[pi * 16 + pj] = 1;

        // 累加
        goalsFor[ia] += ga; goalsAgainst[ia] += gb;
        goalsFor[ib] += gb; goalsAgainst[ib] += ga;

        // 计分
        if (ga > gb) points[ia] += 3;
        else if (ga < gb) points[ib] += 3;
        else { points[ia]++; points[ib]++; }
    }

    // 4. 检查比赛场次
    int maxMatches = teamNum * (teamNum - 1) / 2;
    if (matchesSize > maxMatches) {
        *returnSize = 0;
        return NULL;
    }

    // 5. 检查每对队伍是否都有比赛
    for (int i = 0; i < teamCount; i++) {
        for (int j = i + 1; j < teamCount; j++) {
            if (!played[i * 16 + j]) {
                *returnSize = 0;
                return NULL;
            }
        }
    }

    // 6. 检查积分+净胜球并列
    for (int i = 0; i < teamCount; i++) {
        for (int j = i + 1; j < teamCount; j++) {
            int gdI = goalsFor[i] - goalsAgainst[i];
            int gdJ = goalsFor[j] - goalsAgainst[j];
            if (points[i] == points[j] && gdI == gdJ) {
                *returnSize = 0;
                return NULL;
            }
        }
    }

    // 7. 冒泡排序（按积分降序、净胜球降序）
    int order[16];
    for (int i = 0; i < teamCount; i++) order[i] = i;
    for (int i = 0; i < teamCount; i++) {
        for (int j = i + 1; j < teamCount; j++) {
            int pi = points[order[i]], pj = points[order[j]];
            int gdI = goalsFor[order[i]] - goalsAgainst[order[i]];
            int gdJ = goalsFor[order[j]] - goalsAgainst[order[j]];
            if (pi < pj || (pi == pj && gdI < gdJ)) {
                int tmp = order[i];
                order[i] = order[j];
                order[j] = tmp;
            }
        }
    }

    // 8. 构造返回数组（前三名）
    *returnSize = 3;
    char** result = (char**)malloc(4 * sizeof(char*));
    for (int i = 0; i < 3; i++) {
        result[i] = teams[order[i]];
    }
    result[3] = NULL;  // NULL 结尾
    return result;
}
